import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { dashboardAPI } from '../../services/api';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';
import { Users, ClipboardList, BookOpen, CheckCircle, User, TrendingUp, Calendar, Award, AlertTriangle } from 'lucide-react';
import toast from 'react-hot-toast';

const TeacherDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getStats();
      if (response.data && response.data.success) {
        setStats(response.data.stats);
      } else {
        console.warn('Unexpected response format:', response.data);
        setStats({
          advisoryCount: 25,
          violationsEncoded: 12,
          capstoneRequests: 3,
          isCapstoneAdviser: true,
          advisorySection: 'BSIT-3A',
          recentViolations: [
            {
              id: 1,
              first_name: 'John',
              last_name: 'Doe',
              student_id: '2023-1001',
              violation_type: 'Late Submission',
              date: '2024-01-15',
              status: 'Pending'
            },
            {
              id: 2,
              first_name: 'Jane',
              last_name: 'Smith',
              student_id: '2023-1002',
              violation_type: 'Absence',
              date: '2024-01-14',
              status: 'Resolved'
            }
          ]
        });
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      toast.error('Failed to load dashboard data. Using fallback data.');
      // Set fallback data to prevent crashes
      setStats({
        advisoryCount: 0,
        violationsEncoded: 0,
        capstoneRequests: 0,
        isCapstoneAdviser: false,
        advisorySection: 'N/A',
        recentViolations: []
      });
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Header */}
      <div className="bg-gradient-to-br from-blue-600 via-indigo-600 to-purple-700 rounded-2xl p-6 text-white relative overflow-hidden shadow-2xl">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="absolute bottom-0 left-0 w-24 h-24 bg-white/5 rounded-full translate-y-1/2 -translate-x-1/2"></div>
        <div className="relative z-10 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-20 h-20 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center overflow-hidden shadow-xl ring-4 ring-white/10">
              <User className="w-10 h-10 text-white" />
            </div>
            <div className="flex-1">
              <div className="flex items-center gap-2 text-blue-100 mb-2">
                <User className="w-4 h-4" />
                <span className="text-sm font-medium tracking-wide">Teacher Dashboard</span>
              </div>
              <h1 className="text-3xl font-bold text-white leading-tight mb-1">
                Welcome, {user?.firstName || user?.first_name || 'Teacher'}!
              </h1>
              <p className="text-blue-100 text-sm leading-relaxed">
                {stats?.advisorySection && <span className="font-medium">Advisory: Section {stats.advisorySection}</span>}
                {stats?.isCapstoneAdviser && <span className="ml-2">• Capstone Adviser Available</span>}
              </p>
            </div>
          </div>
          <div className="text-right">
            <div className="inline-flex items-center gap-2 bg-white/20 backdrop-blur-sm px-4 py-2 rounded-full shadow-lg">
              <span className="text-blue-100 text-sm font-medium">Welcome back!</span>
              <span className="text-white font-bold text-base">{new Date().toLocaleDateString('en-US', { weekday: 'short' })}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
        <StatCard
          title="Advisory Students"
          value={stats?.advisoryCount || 0}
          icon={Users}
          color="blue"
          subtitle="Under your advisory"
        />
        <StatCard
          title="Violations Encoded"
          value={stats?.violationsEncoded || 0}
          icon={ClipboardList}
          color="orange"
          subtitle="Total recorded"
        />
        <StatCard
          title="Capstone Requests"
          value={stats?.capstoneRequests || 0}
          icon={BookOpen}
          color="purple"
          subtitle="Pending requests"
        />
        <StatCard
          title="Capstone Status"
          value={stats?.isCapstoneAdviser ? 'Available' : 'Unavailable'}
          icon={CheckCircle}
          color={stats?.isCapstoneAdviser ? 'green' : 'red'}
          subtitle="Adviser availability"
        />
      </div>

      {/* Teacher Info Cards */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card title="Teacher Information" icon={User}>
          <div className="space-y-4">
            {[
              { label: 'Name', value: `${user?.firstName || user?.first_name || 'N/A'} ${user?.lastName || user?.last_name || ''}`.trim(), icon: '👨‍🏫' },
              { label: 'Email', value: user?.email || 'N/A', icon: '📧' },
              { label: 'Department', value: 'College of Computer Studies', icon: '🏢' },
              { label: 'Advisory Section', value: stats?.advisorySection || 'N/A', icon: '👥' }
            ].map((item, index) => (
              <div key={index} className="flex justify-between items-center py-3 px-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-100 dark:border-blue-800 hover:bg-blue-100 dark:hover:bg-blue-900/30 transition-colors">
                <div className="flex items-center gap-2">
                  <span className="text-lg">{item.icon}</span>
                  <span className="text-sm font-medium text-blue-700 dark:text-blue-300">{item.label}</span>
                </div>
                <span className="font-semibold text-blue-900 dark:text-blue-100">{item.value}</span>
              </div>
            ))}
          </div>
        </Card>

        <Card title="Teaching Statistics" icon={TrendingUp}>
          <div className="space-y-4">
            {[
              { label: 'Total Students', value: stats?.advisoryCount || 0, icon: '👥' },
              { label: 'Violations Recorded', value: stats?.violationsEncoded || 0, icon: '📝' },
              { label: 'Capstone Advisees', value: stats?.capstoneRequests || 0, icon: '🎓' },
              { label: 'Adviser Status', value: stats?.isCapstoneAdviser ? 'Available' : 'Unavailable', icon: '✅' }
            ].map((item, index) => (
              <div key={index} className="flex justify-between items-center py-3 px-4 bg-indigo-50 dark:bg-indigo-900/20 rounded-lg border border-indigo-100 dark:border-indigo-800 hover:bg-indigo-100 dark:hover:bg-indigo-900/30 transition-colors">
                <div className="flex items-center gap-2">
                  <span className="text-lg">{item.icon}</span>
                  <span className="text-sm font-medium text-indigo-700 dark:text-indigo-300">{item.label}</span>
                </div>
                <span className="font-semibold text-indigo-900 dark:text-indigo-100">{item.value}</span>
              </div>
            ))}
          </div>
        </Card>
      </div>

      {/* Recent Violations */}
      <Card title="Recent Violations Encoded" icon={ClipboardList}>
        {stats?.recentViolations?.length > 0 ? (
          <div className="space-y-3">
            {stats.recentViolations.map((violation) => (
              <div
                key={violation.id}
                className="flex items-center justify-between p-4 bg-gradient-to-r from-orange-50 to-red-50 dark:from-orange-900/20 dark:to-red-900/20 rounded-xl border border-orange-200 dark:border-orange-800 hover:shadow-md transition-all duration-200"
              >
                <div className="flex items-center gap-3">
                  <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                    violation.status === 'Pending' 
                      ? 'bg-gradient-to-br from-orange-500 to-red-600 text-white' 
                      : 'bg-gradient-to-br from-green-500 to-emerald-600 text-white'
                  }`}>
                    <AlertTriangle className="w-5 h-5" />
                  </div>
                  <div>
                    <p className="font-medium text-gray-900 dark:text-gray-100">
                      {violation.first_name} {violation.last_name}
                    </p>
                    <p className="text-sm text-gray-500 dark:text-gray-400">
                      {violation.student_id} • {violation.violation_type}
                    </p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm text-gray-500 dark:text-gray-400 mb-1">{violation.date}</p>
                  <span className={`px-3 py-1 rounded-full text-xs font-semibold ${
                    violation.status === 'Pending' 
                      ? 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300' 
                      : 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300'
                  }`}>
                    {violation.status}
                  </span>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="py-12 text-center">
            <div className="inline-flex items-center gap-3 px-6 py-4 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 rounded-xl border border-blue-200 dark:border-blue-800">
              <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full flex items-center justify-center text-white">
                <ClipboardList className="w-6 h-6" />
              </div>
              <div>
                <h3 className="font-semibold text-blue-700 dark:text-blue-300">No Violations Yet</h3>
                <p className="text-sm text-blue-600 dark:text-blue-400">Start recording student violations</p>
              </div>
            </div>
          </div>
        )}
      </Card>
    </div>
  );
};

export default TeacherDashboard;
